from abc import ABC, abstractmethod

class Traveler(ABC):
    @abstractmethod
    def book_ticket(self):
        pass

    @abstractmethod
    def cancel_ticket(self):
        pass

class CorporateTraveler(Traveler):
    def __init__(self, id, name, contact, company_name):
        self.id = id
        self.name = name
        self.contact = contact
        self.company_name = company_name

    def book_corporate_ticket(self):
        print(f"Corporate-specific booking logic for company {self.company_name}")

    def cancel_corporate_ticket(self):
        print(f"Corporate-specific cancellation logic for company {self.company_name}")

    def book_ticket(self):
        self.book_corporate_ticket()
        print(f"Corporate booking successful for traveler {self.name} with company {self.company_name}.")

    def cancel_ticket(self):
        self.cancel_corporate_ticket()
        print(f"Corporate booking cancelled for traveler {self.name} with company {self.company_name}.")

def default_test():
    corporate_traveler = CorporateTraveler(1, "John Doe", "123-456-7890", "Acme Corp")
    corporate_traveler.book_corporate_ticket()
    corporate_traveler.cancel_corporate_ticket()
    corporate_traveler.book_ticket()
    corporate_traveler.cancel_ticket()
